  event.addAdvanced("abundance:flowering_jacaranda_hedge", (item, advanced, text) => insertAscendantRarityLine(text, buildAscendantRarityLines(ASCENDANT_RARITY_TOOLTIPS["abundance:flowering_jacaranda_hedge"])))
